import { graphql, useStaticQuery } from 'gatsby';
import * as React from 'react';
import 'src/styles/tokens.css';
import './layout.css';

import { ReactNode } from 'react';
import {
  Container,
  Footer,
  FooterInner,
  FooterLeft,
  FooterLogo,
  FooterCopyright,
  FooterRight,
} from 'src/styles/LayoutStyles';
import Header from './GlobalHeader';

const Layout = ({ children }: { children: ReactNode }) => {
  useStaticQuery(graphql`
    query SiteTitleQuery {
      site {
        siteMetadata {
          title
        }
      }
    }
  `);

  return (
    <>
      <Header />
      <Container>
        <main>{children}</main>
      </Container>
      <Footer>
        <FooterInner>
          <FooterLeft>
            <FooterLogo>
              <span className="dot" />
              Dev.log
            </FooterLogo>
            <FooterCopyright>
              © {new Date().getFullYear()} Dev.log · 개발을 기록하는 공간
            </FooterCopyright>
          </FooterLeft>
          <FooterRight>
            <span>Built with Gatsby</span>
            <span className="sep">·</span>
            <span>Deployed on GitHub Pages</span>
          </FooterRight>
        </FooterInner>
      </Footer>
    </>
  );
};

export default Layout;
